'use strict';
const fs = require('fs');
const path = require('path');

const url = process.env.CHAT_WS_URL || '';
const outPath = path.join(__dirname, '..', 'public', 'config.js');
fs.writeFileSync(
  outPath,
  '// Generated by scripts/write-ws-config.js (set CHAT_WS_URL when building for Vercel)\n' +
    `window.__CHAT_WS_URL__ = ${JSON.stringify(url)};\n`
);
console.log('Wrote public/config.js', url ? '(CHAT_WS_URL set)' : '(empty — same-origin WebSocket)');
